import { ethers } from 'ethers';

const input = '';

const abi = [
  'function createPremiumJobWithDiscovery((uint256,uint256,uint256,string,uint8,bytes32,string),(uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256,uint256,string))'
];

const iface = new ethers.Interface(abi);
const decoded = iface.parseTransaction({ data: input });
const [job, proc] = decoded.args;

function hexToAscii(hex) {
  let str = '';
  for (let i = 0; i < hex.length; i += 2) {
    const c = parseInt(hex.slice(i, i + 2), 16);
    if (c === 0) break;
    str += String.fromCharCode(c);
  }
  return str;
}

